proof fn phi_2_entry_sizes_aligned_uses_external(arch: Arch, i: nat, j: nat)
    requires
        arch.inv(),
        i <= j,
        j < arch.layers.len(),
    ensures
        aligned(arch.entry_size(i), arch.entry_size(j)),
{
    arch.lemma_entry_sizes_aligned(i, j);
}

proof fn phi_4_self_aligned_from_lemma(arch: Arch, i: nat)
    requires
        arch.inv(),
        i < arch.layers.len(),
    ensures
        aligned(arch.entry_size(i), arch.entry_size(i)),
{
    arch.lemma_entry_sizes_aligned(i, i);
}

proof fn phi_5_adjacent_alignment_from_inv(arch: Arch, i: nat)
    requires
        arch.inv(),
        i + 1 < arch.layers.len(),
    ensures
        arch.entry_size(i) % arch.entry_size(i + 1) == 0,
{
    arch.lemma_entry_sizes_aligned(i, i + 1);
}
